import{_ as t,c as a,o as s,a1 as l}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"What Is OpenSkills: Unified Skill Loader | OpenSkills","description":"Learn how OpenSkills enables Claude Code, Cursor, Windsurf, and Aider to share skills via a unified loader. Master progressive loading and multi-agent support.","frontmatter":{"title":"What Is OpenSkills: Unified Skill Loader | OpenSkills","sidebarTitle":"What Is OpenSkills","subtitle":"What Is OpenSkills: Unified Skill Loader","description":"Learn how OpenSkills enables Claude Code, Cursor, Windsurf, and Aider to share skills via a unified loader. Master progressive loading and multi-agent support.","tags":["Concept Introduction","Core Concepts"],"prerequisite":[],"order":2},"headers":[],"relativePath":"numman-ali/openskills/start/what-is-openskills/index.md","filePath":"numman-ali/openskills/start/what-is-openskills/index.md"}'),i={name:"numman-ali/openskills/start/what-is-openskills/index.md"};function n(o,e,r,d,h,p){return s(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="what-is-openskills" tabindex="-1">What Is OpenSkills? <a class="header-anchor" href="#what-is-openskills" aria-label="Permalink to &quot;What Is OpenSkills?&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand OpenSkills&#39;s core value and working principles</li><li>Know the relationship between OpenSkills and Claude Code</li><li>Determine when to use OpenSkills instead of built-in skill systems</li><li>Learn how to enable multiple AI coding agents to share a skill ecosystem</li></ul><div class="info custom-block"><p class="custom-block-title">Prerequisites</p><p>This tutorial assumes you have basic knowledge of AI coding tools (like Claude Code, Cursor, etc.), but requires no prior OpenSkills experience.</p></div><hr><h2 id="your-current-challenges" tabindex="-1">Your Current Challenges <a class="header-anchor" href="#your-current-challenges" aria-label="Permalink to &quot;Your Current Challenges&quot;">​</a></h2><p>You may encounter these scenarios:</p><ul><li><strong>Skills that work smoothly in Claude Code disappear when you switch AI tools</strong>: For example, the PDF processing skill available in Claude Code is unavailable in Cursor</li><li><strong>Installing skills repeatedly across different tools</strong>: Each AI tool requires separate skill configuration, resulting in high management overhead</li><li><strong>Want to use private skills, but the official Marketplace doesn&#39;t support it</strong>: Company-internal or self-developed skills cannot be easily shared with your team</li></ul><p>These problems fundamentally stem from: <strong>Inconsistent skill formats, making cross-tool sharing impossible</strong>.</p><hr><h2 id="core-idea-unified-skill-format" tabindex="-1">Core Idea: Unified Skill Format <a class="header-anchor" href="#core-idea-unified-skill-format" aria-label="Permalink to &quot;Core Idea: Unified Skill Format&quot;">​</a></h2><p>OpenSkills&#39;s core idea is simple: <strong>Transform Claude Code&#39;s skill system into a universal skill loader</strong>.</p><h3 id="what-it-is" tabindex="-1">What It Is <a class="header-anchor" href="#what-it-is" aria-label="Permalink to &quot;What It Is&quot;">​</a></h3><p><strong>OpenSkills</strong> is a universal loader for Anthropic&#39;s skill system, enabling any AI coding agent (Claude Code, Cursor, Windsurf, Aider, etc.) to use skills in the standard SKILL.md format.</p><p>Simply put: <strong>One installer serving all AI coding tools</strong>.</p><h3 id="what-problems-it-solves" tabindex="-1">What Problems It Solves <a class="header-anchor" href="#what-problems-it-solves" aria-label="Permalink to &quot;What Problems It Solves&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Problem</th><th>Solution</th></tr></thead><tbody><tr><td>Inconsistent skill formats</td><td>Use Claude Code&#39;s standard SKILL.md format</td></tr><tr><td>Skills cannot be shared across tools</td><td>Generate unified AGENTS.md that all tools can read</td></tr><tr><td>Distributed skill management</td><td>Unified install, update, and delete commands</td></tr><tr><td>Private skills are hard to share</td><td>Support installation from local paths and private git repositories</td></tr></tbody></table><hr><h2 id="core-values" tabindex="-1">Core Values <a class="header-anchor" href="#core-values" aria-label="Permalink to &quot;Core Values&quot;">​</a></h2><p>OpenSkills provides the following core values:</p><h3 id="_1-unified-standard" tabindex="-1">1. Unified Standard <a class="header-anchor" href="#_1-unified-standard" aria-label="Permalink to &quot;1. Unified Standard&quot;">​</a></h3><p>All agents use the same skill format and AGENTS.md descriptions—no need to learn new formats.</p><ul><li><strong>Fully compatible with Claude Code</strong>: Same prompt format, same Marketplace, same folder structure</li><li><strong>Standardized SKILL.md</strong>: Clear skill definitions, easy to develop and maintain</li></ul><h3 id="_2-progressive-loading" tabindex="-1">2. Progressive Loading <a class="header-anchor" href="#_2-progressive-loading" aria-label="Permalink to &quot;2. Progressive Loading&quot;">​</a></h3><p>Load skills on demand to keep AI context concise.</p><ul><li>No need to load all skills at once</li><li>AI agents dynamically load relevant skills based on task requirements</li><li>Avoid context explosion and improve response quality</li></ul><h3 id="_3-multi-agent-support" tabindex="-1">3. Multi-Agent Support <a class="header-anchor" href="#_3-multi-agent-support" aria-label="Permalink to &quot;3. Multi-Agent Support&quot;">​</a></h3><p>One skill set serves multiple agents, no need for repeated installation.</p><ul><li>Claude Code, Cursor, Windsurf, Aider share the same skill set</li><li>Unified skill management interface</li><li>Reduced configuration and maintenance costs</li></ul><h3 id="_4-open-source-friendly" tabindex="-1">4. Open-Source Friendly <a class="header-anchor" href="#_4-open-source-friendly" aria-label="Permalink to &quot;4. Open-Source Friendly&quot;">​</a></h3><p>Support local paths and private git repositories, suitable for team collaboration.</p><ul><li>Install skills from local file system (in development)</li><li>Install from private git repositories (company-internal sharing)</li><li>Skills can be version-controlled together with projects</li></ul><h3 id="_5-local-execution" tabindex="-1">5. Local Execution <a class="header-anchor" href="#_5-local-execution" aria-label="Permalink to &quot;5. Local Execution&quot;">​</a></h3><p>No data upload, privacy and security guaranteed.</p><ul><li>All skill files stored locally</li><li>No dependency on cloud services, no risk of data leakage</li><li>Suitable for sensitive projects and enterprise environments</li></ul><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>OpenSkills&#39;s workflow is straightforward, divided into three steps:</p><h3 id="step-1-install-skills" tabindex="-1">Step 1: Install Skills <a class="header-anchor" href="#step-1-install-skills" aria-label="Permalink to &quot;Step 1: Install Skills&quot;">​</a></h3><p>Install skills to your project from GitHub, local paths, or private git repositories.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install from Anthropic&#39;s official repository</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropics/skills</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install from local path</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./my-skills</span></span></code></pre></div><p>Skills will be installed to the project&#39;s <code>.claude/skills/</code> directory (default), or <code>.agent/skills/</code> directory (when using <code>--universal</code>).</p><h3 id="step-2-sync-to-agents-md" tabindex="-1">Step 2: Sync to AGENTS.md <a class="header-anchor" href="#step-2-sync-to-agents-md" aria-label="Permalink to &quot;Step 2: Sync to AGENTS.md&quot;">​</a></h3><p>Synchronize installed skills to the AGENTS.md file, generating a skill list that AI agents can read.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span></span></code></pre></div><p>AGENTS.md will contain XML similar to this:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">available_skills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;pdf&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Comprehensive PDF manipulation toolkit for extracting text and tables...&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">location</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;project&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">location</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">available_skills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="step-3-ai-agent-loads-skills" tabindex="-1">Step 3: AI Agent Loads Skills <a class="header-anchor" href="#step-3-ai-agent-loads-skills" aria-label="Permalink to &quot;Step 3: AI Agent Loads Skills&quot;">​</a></h3><p>When an AI agent needs to use a skill, it loads the skill content via the following command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> read</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skill-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>The AI agent will dynamically load the skill content into context and execute the task.</p><hr><h2 id="relationship-with-claude-code" tabindex="-1">Relationship with Claude Code <a class="header-anchor" href="#relationship-with-claude-code" aria-label="Permalink to &quot;Relationship with Claude Code&quot;">​</a></h2><p>OpenSkills and Claude Code are complementary, not substitutes.</p><h3 id="fully-compatible-formats" tabindex="-1">Fully Compatible Formats <a class="header-anchor" href="#fully-compatible-formats" aria-label="Permalink to &quot;Fully Compatible Formats&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Claude Code</th><th>OpenSkills</th></tr></thead><tbody><tr><td><strong>Prompt format</strong></td><td><code>&lt;available_skills&gt;</code> XML</td><td>Same XML</td></tr><tr><td><strong>Skill storage</strong></td><td><code>.claude/skills/</code></td><td><code>.claude/skills/</code> (default)</td></tr><tr><td><strong>Skill invocation</strong></td><td><code>Skill(&quot;name&quot;)</code> tool</td><td><code>npx openskills read &lt;name&gt;</code></td></tr><tr><td><strong>Marketplace</strong></td><td>Anthropic marketplace</td><td>GitHub (anthropics/skills)</td></tr><tr><td><strong>Progressive loading</strong></td><td>✅</td><td>✅</td></tr></tbody></table><h3 id="usage-scenario-comparison" tabindex="-1">Usage Scenario Comparison <a class="header-anchor" href="#usage-scenario-comparison" aria-label="Permalink to &quot;Usage Scenario Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scenario</th><th>Recommended Tool</th><th>Reason</th></tr></thead><tbody><tr><td>Only using Claude Code</td><td>Claude Code built-in</td><td>No extra installation needed, official support</td></tr><tr><td>Mixing multiple AI tools</td><td>OpenSkills</td><td>Unified management, avoid duplication</td></tr><tr><td>Need private skills</td><td>OpenSkills</td><td>Supports local and private repositories</td></tr><tr><td>Team collaboration</td><td>OpenSkills</td><td>Skills can be version-controlled, easy to share</td></tr></tbody></table><hr><h2 id="installation-location-guide" tabindex="-1">Installation Location Guide <a class="header-anchor" href="#installation-location-guide" aria-label="Permalink to &quot;Installation Location Guide&quot;">​</a></h2><p>OpenSkills supports three installation locations:</p><table tabindex="0"><thead><tr><th>Installation Location</th><th>Command</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Project-local</strong></td><td>Default</td><td>Single project use, skills version-controlled with project</td></tr><tr><td><strong>Global installation</strong></td><td><code>--global</code></td><td>All projects share common skills</td></tr><tr><td><strong>Universal mode</strong></td><td><code>--universal</code></td><td>Multi-agent environment, avoid conflicts with Claude Code</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">When to use Universal mode?</p><p>If you use both Claude Code and other AI coding agents (like Cursor, Windsurf), use <code>--universal</code> to install to <code>.agent/skills/</code>. This allows multiple agents to share the same skill set and avoids conflicts.</p></div><hr><h2 id="skill-ecosystem" tabindex="-1">Skill Ecosystem <a class="header-anchor" href="#skill-ecosystem" aria-label="Permalink to &quot;Skill Ecosystem&quot;">​</a></h2><p>OpenSkills uses the same skill ecosystem as Claude Code:</p><h3 id="official-skills-repository" tabindex="-1">Official Skills Repository <a class="header-anchor" href="#official-skills-repository" aria-label="Permalink to &quot;Official Skills Repository&quot;">​</a></h3><p>Anthropic&#39;s officially maintained skills repository: <a href="https://github.com/anthropics/skills" target="_blank" rel="noreferrer">anthropics/skills</a></p><p>Includes common skills:</p><ul><li>PDF processing</li><li>Image generation</li><li>Data analysis</li><li>And more...</li></ul><h3 id="community-skills" tabindex="-1">Community Skills <a class="header-anchor" href="#community-skills" aria-label="Permalink to &quot;Community Skills&quot;">​</a></h3><p>Any GitHub repository can serve as a skill source, as long as it contains a SKILL.md file.</p><h3 id="custom-skills" tabindex="-1">Custom Skills <a class="header-anchor" href="#custom-skills" aria-label="Permalink to &quot;Custom Skills&quot;">​</a></h3><p>You can create your own skills using the standard format and share them with your team.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>OpenSkills&#39;s core idea is:</p><ol><li><strong>Unified standard</strong>: Use Claude Code&#39;s SKILL.md format</li><li><strong>Multi-agent support</strong>: Enable all AI coding tools to share a skill ecosystem</li><li><strong>Progressive loading</strong>: Load on demand, keep context concise</li><li><strong>Local execution</strong>: No data upload, privacy and security guaranteed</li><li><strong>Open-source friendly</strong>: Support local and private repositories</li></ol><p>With OpenSkills, you can:</p><ul><li>Switch seamlessly between different AI tools</li><li>Manage all skills uniformly</li><li>Use and share private skills</li><li>Improve development efficiency</li></ul><hr><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../installation/">Installing OpenSkills Tool</a></strong></p><p>You&#39;ll learn:</p><ul><li>How to check Node.js and Git environments</li><li>Install OpenSkills using npx or globally</li><li>Verify successful installation</li><li>Resolve common installation issues</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Core type definitions</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L1-L24" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>1-24</td></tr><tr><td>Skill interface (Skill)</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L1-L6" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>1-6</td></tr><tr><td>Skill location interface (SkillLocation)</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L8-L12" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>8-12</td></tr><tr><td>Install options interface (InstallOptions)</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L14-L18" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>14-18</td></tr><tr><td>Skill metadata interface (SkillMetadata)</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L20-L24" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>20-24</td></tr></tbody></table><p><strong>Key interfaces</strong>:</p><ul><li><code>Skill</code>: Installed skill information (name, description, location, path)</li><li><code>SkillLocation</code>: Skill lookup location information (path, baseDir, source)</li><li><code>InstallOptions</code>: Install command options (global, universal, yes)</li><li><code>SkillMetadata</code>: Skill metadata (name, description, context)</li></ul><p><strong>Core concept source</strong>:</p><ul><li>README.md:22-86 - &quot;What Is OpenSkills?&quot; section</li></ul></details>`,86)])])}const u=t(i,[["render",n]]);export{k as __pageData,u as default};
